import PriorityQueue from 'priorityqueuejs';

function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    let maxScore = -1;
    const heap = new PriorityQueue((a, b) => {
        if (a[0] !== b[0]) {
            return b[0] - a[0]; // max heap for min edge cost
        } else {
            return a[1] - b[1]; // min heap for total cost
        }
    });

    heap.enq([Infinity, 0, 0]); // [minEdge, totalCost, node]

    while (!heap.isEmpty()) {
        const [currentMin, currentCost, u] = heap.deq();
        if (u === n - 1) {
            if (currentCost <= k) {
                maxScore = Math.max(maxScore, currentMin);
                continue;
            }
        }
        if (currentCost > k) {
            continue;
        }
        for (const [v, cost] of adj[u]) {
            if (v !== n - 1 && !online[v]) {
                continue;
            }
            const newMin = Math.min(currentMin, cost);
            const newTotal = currentCost + cost;
            if (newTotal > k) {
                continue;
            }
            heap.enq([newMin, newTotal, v]);
        }
    }

    return maxScore === Infinity ? -1 : maxScore;
}

