            return minEdge < other.minEdge; // Max heap for minEdge
        } else {
            return totalCost > other.totalCost; // Min heap for totalCost
        }
    }
};

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<int, long long>>> adj(n);
    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        long long cost = edge[2];
        adj[u].emplace_back(v, cost);
    }

    long long maxScore = -1;
    priority_queue<State> pq;
    pq.push({LLONG_MAX, 0, 0});

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();
        long long currentMin = current.minEdge;
        long long currentCost = current.totalCost;
        int u = current.node;

        if (u == n - 1) {
            if (currentCost <= k) {
                maxScore = max(maxScore, currentMin);
                continue;
            }
        }
        if (currentCost > k) {
            continue;
        }
        for (const auto& neighbor : adj[u]) {
            int v = neighbor.first;
            long long cost = neighbor.second;
            if (v != n - 1 && !online[v]) {
                continue;
            }
            long long newMin = min(currentMin, cost);
            long long newTotal = currentCost + cost;
            if (newTotal > k) {
                continue;
            }
            pq.push({newMin, newTotal, v});
        }
    }

    return maxScore == LLONG_MAX ? -1 : maxScore;
}
